#include<bits/stdc++.h>
using namespace std;

int n;
map<int, int> a;
vector<int> v1;
vector<int> v2;
int find(int x) {
	if (a[x] == 0) {
		return x;
	} else {
		return a[x] = find(a[x]);
	}
}
void solve() {
	cin >> n;
	a.clear();

	v1.clear();
	v2.clear();
	for (int i = 1; i <= n; i++) {
		bool e;
		int  b, c;
		cin >> b >> c >> e;
		if (e == 1) {
			int dx = find(b);
			int dy = find(c);
			if (dx != dy) {
				a[dx] = dy;
			}
		} else {
			v1.push_back(b);
			v2.push_back(c);
		}
	}
	for (int i = 0; i < v1.size(); i++) {
		if (find(v1[i]) == find(v2[i])) {
			cout << "NO\n";
			return;
		}
	}
	cout << "YES\n";
	return;
}
int main() {
	int t;
	cin >> t;
	while (t--) solve();
}
